import asyncio
import websockets
from contextlib import suppress

class Item:
    def __init__(self, item_id, owner_id):
        self.item_id = item_id
        self.owner_id = owner_id

class Player:
    def __init__(self, player_id):
        self.player_id = player_id
        self.inventory = []

    def add_item(self, item: Item):
        if not item in self.inventory:
            self.inventory.append(item)

    def remove_item(self, item: Item):
        if item in self.inventory:
            self.inventory.remove(item)

class Server:
    def __init__(self):
        self.players = {}
        self.pending_trades = {}

    async def trade_items(self, web_socket, path):
        async for data in web_socket:
            sender_id, receiver_id, item_id = map(int, data.split())
            if sender_id not in self.players or receiver_id not in self.players:
                continue

            sender = self.players[sender_id]
            receiver = self.players[receiver_id]

            item = next((i for i in sender.inventory if i.item_id == item_id), None)

            if item is None:
                continue

            sender.remove_item(item)
            receiver.add_item(item)

            self.pending_trades[(sender_id, receiver_id, item_id)] = asyncio.create_task(self.confirm_trade(sender, receiver, item))
            await self.pending_trades[(sender_id, receiver_id, item_id)]

    async def confirm_trade(self, sender, receiver, item: Item):
        await asyncio.sleep(3) # Simulate a delay for trade confirmation
        with suppress(KeyError):
            del self.pending_trades[(sender.player_id, receiver.player_id, item.item_id)]

server = Server()

start_server = websockets.serve(server.trade_items, 'localhost', 8765)

asyncio.get_event_loop().run_until_complete(start_server)
asyncio.get_event_loop().run_forever()